DROP TABLE IF EXISTS attendance_record CASCADE;
DROP TABLE IF EXISTS course_week CASCADE;
DROP TABLE IF EXISTS student CASCADE;
CREATE TABLE student (student_no VARCHAR(20) PRIMARY KEY, fname CHAR(1) NOT NULL, lname CHAR(1) NOT NULL);
CREATE TABLE course_week (week_no INTEGER PRIMARY KEY, week_date DATE NOT NULL UNIQUE, topic VARCHAR(200) NOT NULL);
CREATE TABLE attendance_record (student_no VARCHAR(20) NOT NULL, week_no INTEGER NOT NULL, attendance_date DATE NOT NULL, PRIMARY KEY (student_no, week_no), FOREIGN KEY (student_no) REFERENCES student(student_no), FOREIGN KEY (week_no) REFERENCES course_week(week_no));
